const Q_ACCOUNTS_2012=[{"id": "objective>Accounts>2012>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What subject are you doing?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Commerce</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Agricultural science</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Physics</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Accounts</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The subject in question is 'Accounts' as indicated in the id of the question. Therefore, the correct answer is 'Accounts'.</div>", "topic": "INTRODUCTION TO ACCOUNTING : MEANING AND OBJECTIVES OF ACCOUNTING AND BOOKKEEPING"}, {"id": "objective>Accounts>2012>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The base upon which assets of an organization is valued is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">historical concept</div>", "<div style=\"font-family:Cambria;font-size:17px;\">business entity concept</div>", "<div style=\"font-family:Cambria;font-size:17px;\">periodicity concept</div>", "<div style=\"font-family:Cambria;font-size:17px;\">materiality concept </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Historical cost is the value of a resource given up or a liability incurred to acquire an asset/service at the time when the resource was given up or the liability incurred.  <br/>  In subsequent periods when there is appreciation, the value is not recognized as an increase in assets value except where allowed or required by accounting standards.</div>", "topic": "ACCOUNTING RATIO ( 1) : INTRODUCTION AND USES"}, {"id": "objective>Accounts>2012>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An accountant must not only be interested in record keeping but also in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the application of professional competency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the accuracy of postings</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the casting of financial figures </div>", "<div style=\"font-family:Cambria;font-size:17px;\">effective preparation of balance sheet </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The duties of an accountant revolve around financial record keeping, decision making, and other aspects that can ensure that the company thrives well in the market. An accountant must prepare and analyze the financial records of a company while managing data that can be analyzed and used for consultation.</div>", "topic": "INTRODUCTION TO ACCOUNTING : USERS OF ACCOUNTING & ROLES OF ACCOUNTING"}, {"id": "objective>Accounts>2012>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The correct posting in the double entry system of account when there is an increase in assets, expenses, capital or liability is to debit </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">capital and credit liabilities </div>", "<div style=\"font-family:Cambria;font-size:17px;\">liabilities and credit assets</div>", "<div style=\"font-family:Cambria;font-size:17px;\">assets and credit capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital and credit assets</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the double entry system of accounting, an increase in assets or expenses is recorded as a debit, while an increase in capital or liabilities is recorded as a credit. Therefore, the correct posting when there is an increase in assets, expenses, capital or liability is to debit assets and credit capital. This is based on the fundamental principle of double entry bookkeeping where every financial transaction affects at least two accounts and the total debits must equal total credits.</div>", "topic": "PRINCIPLE OF DOUBLE ENTRY : MEANING AND APPLICATION"}, {"id": "objective>Accounts>2012>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The capital of a sole trader can be increased by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">debiting the capital account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">crediting the capital account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">debiting the cash account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">crediting the cash account </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The capital of a sole trader can be increased by crediting the capital account. In accounting, a credit to the capital account means an increase in the owner's equity. This is based on the fundamental accounting equation where Assets = Liabilities + Owner's Equity. When the owner injects more capital into the business, the owner's equity increases, hence the capital account is credited.</div>", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET"}, {"id": "objective>Accounts>2012>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Akirika bought a motor van for his business by cash. The entries are to debit </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">motor van and credit Akirika </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sales and credit Akirika </div>", "<div style=\"font-family:Cambria;font-size:17px;\">motor van and credit cash </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cash and credit motor </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When Akirika bought a motor van for his business by cash, the entries are to debit motor van and credit cash. This is because in accounting, a debit entry signifies an increase in asset (in this case, the motor van) while a credit entry signifies a decrease in asset (in this case, cash). Therefore, the motor van account is debited to show an increase in business assets and the cash account is credited to show a decrease in cash assets.</div>", "topic": "CASH BOOK : MEANING AND TYPES OF CASH BOOK"}, {"id": "objective>Accounts>2012>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the information below to answer this question.  <br/>  Ibrahim, a microbusiness operator, sold 10 bags of sugar to Jide at total cost of ₦12,000. <br/>  <br/> In the stock of Ibrahim, the entry to record the transactions would be to debit</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sugar account ₦12,000 and credit Jide ₦12,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Jide ₦12,000 and credit sales ₦12,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ibrahim ₦12,000 and credit Jide ₦12,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sugar account ₦12,000 and credit Ibrahim ₦12,000</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In accounting, when a sale is made, the seller debits the receivable account and credits the sales account. This is in accordance with the double-entry bookkeeping system, which states that for every financial transaction, corresponding debit and credit entries must be made.</div>", "topic": "SUBSIDIARY BOOKS : MEANING AND IMPORTANCE"}, {"id": "objective>Accounts>2012>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the information below to answer this question.  <br/>  Ibrahim, a microbusiness operator, sold 10 bags of sugar to Jide at total cost of ₦12,000.  <br/> The record in Jide's book would be to debit </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">purchases ₦12,000 and credit Ibrahim ₦12,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Jide ₦12,000 and credit sales account ₦12,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ibrahim ₦12,000 and credit Jide ₦12,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sugar account ₦12,000 and credit Ibrahim ₦12,000</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">From the buyer's perspective, the purchase of goods is an expense, so his purchases account should be debited. At the same time, he owes the seller for the goods, so the seller's account should be credited. This is also in accordance with the double-entry bookkeeping system.</div>", "topic": "PRINCIPLE OF DOUBLE ENTRY : CASH AND CREDIT TRANSACTIONS"}, {"id": "objective>Accounts>2012>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> Cash Book <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"> ₦</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> ₦ <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">capital</td><td style=\"border:1px solid black;text-align:center;\"> 2600</td><td style=\"border:1px solid black;text-align:center;\"> purchases</td><td style=\"border:1px solid black;text-align:center;\"> 15000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Sales</td><td style=\"border:1px solid black;text-align:center;\"> 28200</td><td style=\"border:1px solid black;text-align:center;\"> Rent</td><td style=\"border:1px solid black;text-align:center;\"> 1250 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> Motor vehicle</td><td style=\"border:1px solid black;text-align:center;\"> 7600</td></tr></table></div> <br/> Determine the balance sheet</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦6 950 credit </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦6 950 debit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦6 000 credit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦6 000 debit</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sum both side, we get credit side of ₦ 30,800 and debit side of ₦23,850  <br/>  The bank balance will be a ₦(30,800 - 23,850)  <br/> = ₦6,950 debit.</div>", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET"}, {"id": "objective>Accounts>2012>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a three-column cash book, dishonoured cheques will be shown on the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bank column(debit)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bank column(credit)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cash column(debit)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cash column(credit)</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The dishonour of cheques is recorded on the payment side or credit side of the bank column of cash book. When a cheque is dishonoured, the Bank A/c is credited and, thus, it is credited in the bank column of the cash book.</div>", "topic": "CASH BOOK : THREE COLUMN CASH BOOK"}, {"id": "objective>Accounts>2012>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Date</td><td style=\"border:1px solid black;text-align:center;\"> Particulars</td><td style=\"border:1px solid black;text-align:center;\"> Folio</td><td style=\"border:1px solid black;text-align:center;\"> Details</td><td style=\"border:1px solid black;text-align:center;\"> Total <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">1/6/02</td><td style=\"border:1px solid black;text-align:center;\"> 2 bags of maize</td><td style=\"border:1px solid black;text-align:center;\"> SL</td><td style=\"border:1px solid black;text-align:center;\"> 1 800</td><td style=\"border:1px solid black;text-align:center;\"> 1 800 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">12/6/02</td><td style=\"border:1px solid black;text-align:center;\"> 3 bags of salt</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\">  <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> less 5% discount</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> 7 000</td><td style=\"border:1px solid black;text-align:center;\"> 7 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> 8 800</td></tr></table></div> <br/> The 5% discount shown above indicates</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">trade discount </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cash discount </div>", "<div style=\"font-family:Cambria;font-size:17px;\">discount allowed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">discount received </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The 5% discount shown in the question is a trade discount. A trade discount is a reduction in the listed price of an item when it's sold for resale. It's used to incentivize bulk purchasing. In this case, the discount is given on the purchase of goods, hence it's a trade discount. The other options are incorrect: a cash discount is a reduction in the amount to be paid if the payment is made within a certain period, discount allowed is a reduction in the amount of money received from a debtor, while discount received is a reduction in the amount of money paid to a creditor.</div>", "topic": "SUBSIDIARY BOOKS : SOURCE DOCUMENT"}, {"id": "objective>Accounts>2012>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Cash can be drawn from the bank using</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a bank teller</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a credit card</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a recharge card</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ATM card</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">ATM is a machine that dispenses cash or performs other banking services when an account holder inserts a bank card. For one to withdraw money from the machine, you are required to own an ATM card</div>", "topic": "BANK RECONCILIATION STATEMENT : INTRODUCTION AND REASONS FOR DISAGREENMENT BETWEEN CASH BOOK & BANK STATEMENT"}, {"id": "objective>Accounts>2012>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a modern day banking system, cash transfer cannot be made where the transferor</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">has no sufficient cash with the bank</div>", "<div style=\"font-family:Cambria;font-size:17px;\">has no account with the bank</div>", "<div style=\"font-family:Cambria;font-size:17px;\">does not reside in the bank's country</div>", "<div style=\"font-family:Cambria;font-size:17px;\">doesn't possess the domestic currency. </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If the transferor's bank account does not have sufficient funds to cover the cash transfer, the transfer may be declined. In this case, the transferor needs to have enough money in their account to initiate the transfer.</div>", "topic": "BANK RECONCILIATION STATEMENT : INTRODUCTION AND REASONS FOR DISAGREENMENT BETWEEN CASH BOOK & BANK STATEMENT"}, {"id": "objective>Accounts>2012>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Cash </td><td style=\"border:1px solid black;text-align:center;\"> ₦5 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Discount cheque</td><td style=\"border:1px solid black;text-align:center;\">₦1 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Direct credit</td><td style=\"border:1px solid black;text-align:center;\"> ₦800 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">direct debit </td><td style=\"border:1px solid black;text-align:center;\">₦ 500</td></tr></table></div>  <br/> The adjusted cash book is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦6 300</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦4 300</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦3 700</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦2 700</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The adjusted cash book is calculated by adding the cash, discount cheque, and direct credit, then subtracting the direct debit.  <br/> So, ₦5 000 (Cash) + ₦1 000 (Discount cheque) + ₦800 (Direct credit) - ₦500 (Direct debit)  <br/> = ₦6 300. </div>", "topic": "BANK RECONCILIATION STATEMENT : PREPARATION OF BANK RECONCILIATION STATEMENT"}, {"id": "objective>Accounts>2012>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the information below to answer this question <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"> ₦</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> ₦ <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Stock 1/1</td><td style=\"border:1px solid black;text-align:center;\"> 20000</td><td style=\"border:1px solid black;text-align:center;\"> Net sale</td><td style=\"border:1px solid black;text-align:center;\"> 370000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Add purchases</td><td style=\"border:1px solid black;text-align:center;\"> 250000</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\">  <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Cost of goods</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\">  <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Available for sale</td><td style=\"border:1px solid black;text-align:center;\"> 270000</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> ----- <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">less stock 31/12</td><td style=\"border:1px solid black;text-align:center;\"> 40000</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\">  <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Cost of goods sold</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> 230000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">rent expenses</td><td style=\"border:1px solid black;text-align:center;\"> 35000</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"></td></tr></table></div> <br/>  <br/> Find the gross profit </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦370 000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦230 000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦150 000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦140 000</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Gross profit is calculated by subtracting the cost of goods sold from the net sales.  <br/>  <br/> In this case, the gross profit is ₦370,000 (net sales) - ₦230,000 (cost of goods sold)  <br/> = ₦140,000.</div>", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES"}, {"id": "objective>Accounts>2012>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the information below to answer this question <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"> ₦</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> ₦ <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Stock 1/1</td><td style=\"border:1px solid black;text-align:center;\"> 20000</td><td style=\"border:1px solid black;text-align:center;\"> Net sale</td><td style=\"border:1px solid black;text-align:center;\"> 370000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Add purchases</td><td style=\"border:1px solid black;text-align:center;\"> 250000</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\">  <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Cost of goods</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\">  <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Available for sale</td><td style=\"border:1px solid black;text-align:center;\"> 270000</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> ----- <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">less stock 31/12</td><td style=\"border:1px solid black;text-align:center;\"> 40000</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\">  <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Cost of goods sold</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> 230000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">rent expenses</td><td style=\"border:1px solid black;text-align:center;\"> 35000</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"></td></tr></table></div> <br/> Calculate the net profit</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦35 000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦40 000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦105 000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦115 000</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Net profit is calculated by subtracting the total expenses from the gross profit.  <br/>  <br/> In this case, the net profit is ₦140,000 (gross profit) - ₦35,000 (total expenses)  <br/> = ₦105,000.</div>", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT"}, {"id": "objective>Accounts>2012>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the information below to answer this question. <br/>  At the end of a financial period, the trading, profit and loss account of a sole trader shows a profit of ₦180,000. It is however discovered that revenue of ₦15,000 is recorded as expenses while expenses of ₦4,000 is recorded as revenue. <br/>  <br/> Determine the adjusted net profit </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦210 000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦202 000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦195 000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦184 000</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The adjusted net profit is ₦180,000 + (₦15,000 - ₦4,000) + (₦15,000 - ₦4,000) <br/>  = ₦202 000.</div>", "topic": "CORRECTION OF ERRORS : MEANING AND PROCEDURES"}, {"id": "objective>Accounts>2012>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the information below to answer this question. <br/>  At the end of a financial period, the trading, profit and loss account of a sole trader shows a profit of ₦180,000. It is however discovered that revenue of ₦15,000 is recorded as expenses while expenses of ₦4,000 is recorded as revenue.  <br/> The revenue to be added as an adjustment is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦34 000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦30 000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦15 000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦4 000</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The revenue to be added as an adjustment is ₦15 000 + ₦15 000(to show adjustment)  <br/> = ₦30 000.</div>", "topic": "CORRECTION OF ERRORS : MEANING AND PROCEDURES"}, {"id": "objective>Accounts>2012>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is an item of special assets?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Fixed assets</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Current assets</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Trademark</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gratuity</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Trademark is a special asset. It can also be called an intangible asset. A trademark is any word, name, symbol, or design, or any combination thereof, used in commerce to identify and distinguish the goods of one manufacturer or seller from those of another and to indicate the source of the goods. </div>", "topic": "COMPANY ACCOUNT : INTRODUCTION , TYPES AND KINDS OF COMPANIES"}, {"id": "objective>Accounts>2012>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the information below to answer this question.  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">1/5/07</td><td style=\"border:1px solid black;text-align:center;\"> Purchased 100 bags of milk at ₦10.00k each <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">3/5/07 </td><td style=\"border:1px solid black;text-align:center;\">Purchase 60 bags of milk at ₦11.50k each <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">8/5/07 </td><td style=\"border:1px solid black;text-align:center;\">Issued  85 bags of milk  <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">15/5/07</td><td style=\"border:1px solid black;text-align:center;\"> Purchased 180 bags of milk at #12.80k each <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">22/5/07 </td><td style=\"border:1px solid black;text-align:center;\">Issued 145 bags of milk</td></tr></table></div> <br/>  <br/> using FIFO method, what would be the value of stock as at 9/5/07?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦862.50</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦840.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦806.25</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦750.00</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Using FIFO Method: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">100 @ 10</td><td style=\"border:1px solid black;text-align:center;\"> 1000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">60 @ 11.50</td><td style=\"border:1px solid black;text-align:center;\"> <span style=\"text-decoration:underline;\"> 690 </span></td></tr><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"> 1690</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">85 @ 10</td><td style=\"border:1px solid black;text-align:center;\"> (<span style=\"text-decoration:underline;\"> 850 </span>)</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">closing stock</td><td style=\"border:1px solid black;text-align:center;\"> 840</td></tr></table></div></div>", "topic": "STOCK VALUATION : MEANING OF STOCK VALUATION AND METHODS"}, {"id": "objective>Accounts>2012>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the information below to answer this question.  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">1/5/07</td><td style=\"border:1px solid black;text-align:center;\"> Purchased 100 bags of milk at ₦10.00k each <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">3/5/07 </td><td style=\"border:1px solid black;text-align:center;\">Purchase 60 bags of milk at ₦11.50k each <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">8/5/07 </td><td style=\"border:1px solid black;text-align:center;\">Issued  85 bags of milk  <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">15/5/07</td><td style=\"border:1px solid black;text-align:center;\"> Purchased 180 bags of milk at #12.80k each <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">22/5/07 </td><td style=\"border:1px solid black;text-align:center;\">Issued 145 bags of milk</td></tr></table></div>  <br/> Using simple average method, calculate the value of stock after 22/5/07</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦1 198.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦1 218.38</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦1 257.67</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦1 408.00</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Total purchases = 100 + 60 + 180 <br/> = 340 <br/>  <br/> Total issue = 85 + 145 <br/> = 230 <br/>  <br/> Stock left will be 340 - 230 <br/> =  110  <br/>  <br/> The value will be 110 × ₦12.80  <br/> = ₦1,408</div>", "topic": "STOCK VALUATION : MEANING OF STOCK VALUATION AND METHODS"}, {"id": "objective>Accounts>2012>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The LIFO method has an advantage over FIFO in that stocks are valued at</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">previous prices</div>", "<div style=\"font-family:Cambria;font-size:17px;\">current prices</div>", "<div style=\"font-family:Cambria;font-size:17px;\">average rates</div>", "<div style=\"font-family:Cambria;font-size:17px;\">flat rates </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The advantages of LIFO are: <br/> - It is easy to understand and simple to apply <br/> - It is an actual cost method <br/> - value of issues are close to current economic value <br/> - Stock valuation is usually conservative especially when prices are rising.</div>", "topic": "STOCK VALUATION : MEANING OF STOCK VALUATION AND METHODS"}, {"id": "objective>Accounts>2012>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In sales ledger control account, returns inwards is usually </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">debited and debtors credited</div>", "<div style=\"font-family:Cambria;font-size:17px;\">credited and sales returns debited</div>", "<div style=\"font-family:Cambria;font-size:17px;\">debited and cash credited </div>", "<div style=\"font-family:Cambria;font-size:17px;\">credited and bank credited</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Returns inwards are goods returned to the selling entity by the customer, such as for warranty claims or outright returns of goods for a credit. For the customer, this results in the following accounting transaction. Returns inwards is usually credited and sales returns debited.</div>", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT"}, {"id": "objective>Accounts>2012>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Purchase ledger control account can also be referred to as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sales day book</div>", "<div style=\"font-family:Cambria;font-size:17px;\">purchases day book </div>", "<div style=\"font-family:Cambria;font-size:17px;\">creditors ledger</div>", "<div style=\"font-family:Cambria;font-size:17px;\">debtors ledger</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The purchase ledger control account can also be referred to as the creditors ledger. This is because the purchase ledger control account is a summary account that records the total amount owed to suppliers for goods purchased on credit. These suppliers are the business's creditors, hence the term 'creditors ledger'.</div>", "topic": "CONTROL ACCOUNTS : PURCHASES LEDGER CONTROL ACCOUNT"}, {"id": "objective>Accounts>2012>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a debit item in the sales ledger control account?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cheque receipts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dishonoured cheques</div>", "<div style=\"font-family:Cambria;font-size:17px;\">discount allowed </div>", "<div style=\"font-family:Cambria;font-size:17px;\">bills receivable </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Dishonoured cheques (bill) is a debit item on the sales ledger control account. Others include: Carriage outwards, Debit note issued, Discounts disallowed etc.</div>", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT"}, {"id": "objective>Accounts>2012>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Cash Book (Extract) <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"> ₦</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> ₦ <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Balance b/f</td><td style=\"border:1px solid black;text-align:center;\"> 2 200</td><td style=\"border:1px solid black;text-align:center;\"> Sundry expenses</td><td style=\"border:1px solid black;text-align:center;\"> 16 800 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">receipt from</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> drawings</td><td style=\"border:1px solid black;text-align:center;\"> 4700 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Customers</td><td style=\"border:1px solid black;text-align:center;\"> 16400</td><td style=\"border:1px solid black;text-align:center;\"> Suppliers</td><td style=\"border:1px solid black;text-align:center;\"> 7300</td></tr></table></div> <br/> Debtors opening and closing balance amount to ₦6 500 and ₦7 600 respectively. What is the sales value?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦15 300</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦17 500</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦29 400</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦31 600</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sales will be receipt from customers + amount paid by debtors  <br/> = ₦ 16,400 + ₦(7,600 - 6,500) <br/>  = ₦(16,400 + 1,100)  <br/> = ₦17 500</div>", "topic": "CASH BOOK : MEANING AND TYPES OF CASH BOOK"}, {"id": "objective>Accounts>2012>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Fixtures</td><td style=\"border:1px solid black;text-align:center;\">₦30 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Debtors</td><td style=\"border:1px solid black;text-align:center;\">₦7 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Stock</td><td style=\"border:1px solid black;text-align:center;\">₦8 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Creditors </td><td style=\"border:1px solid black;text-align:center;\">₦3 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Goodwill</td><td style=\"border:1px solid black;text-align:center;\">₦10 000</td></tr></table></div> <br/> Determine the capital.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦10 000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦42 000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦45 000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦52 000</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">On the debit side, we have fixtures + debtors + stock + goodwill = ₦(30,000 + 7,000 + 8,000 + 10,000)  <br/> = ₦55,000  <br/>  <br/>  On the credit side, we have creditors = ₦3,000  <br/>   <br/> =    ₦(55,000 - 3,000)  <br/> = ₦52,000.</div>", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING EQUATION"}, {"id": "objective>Accounts>2012>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In manufacturing accounts,finance expenses are charged to the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">departmental account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">trading account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">profit and loss account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">balance sheet </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In manufacturing accounts, finance expenses are charged to the profit and loss account. This is because finance expenses are considered as operating expenses, which are deducted from the gross profit to arrive at the net profit or loss. The profit and loss account is used to record all the revenues and expenses of a business during a specific period of time.</div>", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE"}, {"id": "objective>Accounts>2012>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the information below to answer this question. <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Total production cost</td><td style=\"border:1px solid black;text-align:center;\"> 360 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Factory overhead cost</td><td style=\"border:1px solid black;text-align:center;\"> 56 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Selling price per unit </td><td style=\"border:1px solid black;text-align:center;\">120</td></tr></table></div> <br/> Production volume 4 000 units <br/>  <br/> What is the total manufacturing profit?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦64 000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦120 000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦360 000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦480 000. </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Gross sales = 4,000 × 120  <br/> = ₦480,000 <br/>  <br/> total manufacturing profit = gross sales - total production cost  <br/> = ₦480,000 - ₦360,000 <br/>  = ₦120,000.</div>", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE"}, {"id": "objective>Accounts>2012>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the information below to answer this question. <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Total production cost</td><td style=\"border:1px solid black;text-align:center;\"> 360 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Factory overhead cost</td><td style=\"border:1px solid black;text-align:center;\"> 56 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Selling price per unit </td><td style=\"border:1px solid black;text-align:center;\">120</td></tr></table></div> <br/> Production volume 4 000 units  <br/> Determine the value of prime cost.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦416 000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦304 000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦240 000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦184 000</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The prime cost is the total production cost minus the factory overhead cost.  <br/> Therefore, the prime cost is 360,000 - 56,000  <br/> = 304,000.</div>", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE"}, {"id": "objective>Accounts>2012>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The excess of revenue over expenditure is charged to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">profit and loss account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">revenue account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">accumulation fund</div>", "<div style=\"font-family:Cambria;font-size:17px;\">income and expenditure account </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The excess of revenue over expenditure is charged to the accumulation fund. The accumulation fund is a reserve account in which the surplus of income over expenditure is accumulated. It is used to finance future growth and expansion.</div>", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS"}, {"id": "objective>Accounts>2012>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> Receipt and Payment Accounts (Extract) <br/>  <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Date</td><td style=\"border:1px solid black;text-align:center;\"> Receipts</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> Date</td><td style=\"border:1px solid black;text-align:center;\"> Payments</td><td style=\"border:1px solid black;text-align:center;\">  <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> ₦</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> ₦ <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">1/9</td><td style=\"border:1px solid black;text-align:center;\"> Balance b/d</td><td style=\"border:1px solid black;text-align:center;\"> 210000</td><td style=\"border:1px solid black;text-align:center;\"> 10/9</td><td style=\"border:1px solid black;text-align:center;\"> Salary</td><td style=\"border:1px solid black;text-align:center;\"> 20000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">5/9</td><td style=\"border:1px solid black;text-align:center;\"> subscriptions</td><td style=\"border:1px solid black;text-align:center;\"> 80000</td><td style=\"border:1px solid black;text-align:center;\"> 15/9</td><td style=\"border:1px solid black;text-align:center;\"> wages</td><td style=\"border:1px solid black;text-align:center;\"> 15000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">30/9</td><td style=\"border:1px solid black;text-align:center;\"> Donations</td><td style=\"border:1px solid black;text-align:center;\"> 60000</td><td style=\"border:1px solid black;text-align:center;\"> 20/9</td><td style=\"border:1px solid black;text-align:center;\"> Donations</td><td style=\"border:1px solid black;text-align:center;\"> 40000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> 20/9</td><td style=\"border:1px solid black;text-align:center;\"> transportation</td><td style=\"border:1px solid black;text-align:center;\"> 10000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\">30/9</td><td style=\"border:1px solid black;text-align:center;\"> Entertainment</td><td style=\"border:1px solid black;text-align:center;\"> 50000</td></tr></table></div> <br/> Determine the balance.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦415 000 debit </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦215 000 credit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦215 000 debit </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦315 000 credit </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Add the debit side= 210000+80000+60000   <br/> = 350000 <br/>  <br/> Add the credit side = 20000+15000+40000+10000+50000  <br/> = 135000 <br/>  <br/> Since the debit side exceeds the credit side we have: 350,000 - 135,000 <br/>  <br/>  = 215,000 debit since the debit side exceeds the credit side.</div>", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : RECEIPTS AND PAYMENTS ACCOUNTS"}, {"id": "objective>Accounts>2012>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main advantage of a departmental account is that its</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">expenses are shared</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gross profit is computed </div>", "<div style=\"font-family:Cambria;font-size:17px;\">net profit is computed </div>", "<div style=\"font-family:Cambria;font-size:17px;\">balance sheet is obtained</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A departmental account is a way of keeping financial records for different departments within a business. The main advantage of this is that it allows for the computation of gross profit for each department. Gross profit is the profit a company makes after deducting the costs associated with making and selling its products, or the costs associated with providing its services. This helps in identifying which department is performing well and which is not, thereby aiding in decision making.</div>", "topic": "DEPARTMENTAL ACCOUNT : INTRODUCTION AND ADVANTAGES OF DEPARTMENTAL ACCOUNT"}, {"id": "objective>Accounts>2012>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> Trading Profit and Loss Account (Extract) <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"> Dep X</td><td style=\"border:1px solid black;text-align:center;\"> <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> ₦</td><td style=\"border:1px solid black;text-align:center;\"> ₦ <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Net sales</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\">  <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Less cost of goods sold</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> 3000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Stock 1/1</td><td style=\"border:1px solid black;text-align:center;\"> 200</td><td style=\"border:1px solid black;text-align:center;\">  <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Purchases</td><td style=\"border:1px solid black;text-align:center;\"> 1000</td><td style=\"border:1px solid black;text-align:center;\">  <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Cost of goods available for sale</td><td style=\"border:1px solid black;text-align:center;\"> 1200</td><td style=\"border:1px solid black;text-align:center;\">  <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Less stock 31/12</td><td style=\"border:1px solid black;text-align:center;\"> 400</td><td style=\"border:1px solid black;text-align:center;\">   <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Cost of goods sold</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> 800</td></tr></table></div> <br/> From the above information, the gross profit for department X is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦3 800</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦2 300</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦2 200</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦2 000</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Gross profit =   Net sales - cost of goods sold  <br/>                 = ₦(3,000 - 800)  <br/>                          = ₦2,200</div>", "topic": "DEPARTMENTAL ACCOUNT : PRESENTATION OF FINAL ACCOUNTS"}, {"id": "objective>Accounts>2012>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the head office ledger, the value of goods sent to the branch are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">debited to the head office current account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">debited to the branch current account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">credited to the head office current account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">credited to the branch current account </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the head office ledger, the value of goods sent to the branch are debited to the branch current account. This is because when the head office sends goods to the branch, it is essentially transferring assets to the branch. In accounting, when assets are increased, they are debited. Therefore, the branch account (which is an asset to the head office) is debited.</div>", "topic": "BRANCH ACCOUNTING : BRANCH ADJUSTMENT METHOD"}, {"id": "objective>Accounts>2012>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following methods of invoicing goods to branches facilitate easy checks on the activities of branches?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cost price</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fixed percentage on cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">selling price</div>", "<div style=\"font-family:Cambria;font-size:17px;\">invoice price</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The method of invoicing goods to branches that facilitates easy checks on the activities of branches is the invoice price method. This is because the invoice price includes both the cost of the goods and the profit margin. This allows the head office to easily track both the cost and the profit margin of the goods sold by the branch, thereby facilitating easy checks on the branch's activities.</div>", "topic": "BRANCH ACCOUNTING : PRICING METHODS"}, {"id": "objective>Accounts>2012>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the information below to answer this question.  <br/>  <br/> The partners capital are: Modibbo ₦60 000 and Jakata ₦90 000. The partners share profit and loss in the ratio of their capital contributions. The net profit for the year is ₦12 000 <br/>  <br/> Find Modibbo's share of the profit. </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦6 200</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦4 800</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦4 400</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦4 300</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">ratio of their capital = 60000/90000 <br/>                                         = 2/3 <br/>  <br/> Total ratio = 2+3 = 5 <br/> Modibo's share of profit = 2/5  x 12000 <br/>                                                      = 4800</div>", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR"}, {"id": "objective>Accounts>2012>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the information below to answer this question.  <br/>  <br/> The partners capital are: Modibbo ₦60 000 and Jakata ₦90 000. The partners share profit and loss in the ratio of their capital contributions. The net profit for the year is ₦12 000 <br/> What is Jakata's profit sharing ratio? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3:5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1:2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2:5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1:5</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Jakata's profit sharing ratio is 3:5 which is acsertain from their capital  <br/> i.e 60,000/90,000 = 2/3 <br/>  = 2:3 <br/>  <br/> Therefore, total ratio = 2 + 3  <br/>  = 5</div>", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR"}, {"id": "objective>Accounts>2012>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In what ways can a goodwill be written off in partnership business?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">using the partner's profit and loss sharing ratio</div>", "<div style=\"font-family:Cambria;font-size:17px;\">By neglecting the ratio of partners capital contribution </div>", "<div style=\"font-family:Cambria;font-size:17px;\">by sharing it unequally among the partners where no agreement exists</div>", "<div style=\"font-family:Cambria;font-size:17px;\">by sharing it among the active partners' only </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Raise the goodwill at its value by crediting all the partners' capital accounts (including that of the retired/ deceased partners) and then <br/> Written off by debiting the remaining partners in their new profit sharing ratio and crediting the goodwill account with its full value.</div>", "topic": "GOODWILL ACCOUNTS : TREATMENT OF GOODWILL ON ADMISSION OF PARTNERS AND CHANGES IN RATIO"}, {"id": "objective>Accounts>2012>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Ngozi and Musa with a capital of ₦30 000 each decide to admit Mary into the partnership business with a capital of ₦20 000 and goodwill ₦15 000.  If the profits and losses are to be shared equally, the journal entries to record goodwill are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">debit goodwill ₦15 000, cash ₦20 000 and credit Mary's capital ₦35 000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">credit goodwill ₦15 000, cash ₦20000 and debit mary's capital ₦35 000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">debit goodwill ₦15 000, credit cash ₦20 000 and credit Mary's capital ₦20 000 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">debit old partners capital ₦15 000, credit cash ₦20 000 and Mary's capital ₦35 000 </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When Mary is admitted into the partnership, her capital contribution and goodwill are recorded as debits to the partnership's accounts, as they represent increases in the partnership's assets. The corresponding credit is made to Mary's capital account, reflecting her claim on the partnership's assets.  <br/>  <br/> Therefore, the correct journal entry is to debit goodwill for ₦15 000, debit cash for ₦20 000, and credit Mary's capital for ₦35 000.</div>", "topic": "GOODWILL ACCOUNTS : TREATMENT OF GOODWILL ON ADMISSION OF PARTNERS AND CHANGES IN RATIO"}, {"id": "objective>Accounts>2012>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In converting a partnership into a limited liability company, the necessary accounts to be opened in the books of the company are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">business purchase account and ordinary share capital account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">business purchase account, vendor account and ordinary share capital account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">business purchase account and vendor account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ordinary share capital account, vendor account and unpaid share capital account </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a partnership is converted into a limited liability company, the necessary accounts to be opened in the books of the company are business purchase account, vendor account and ordinary share capital account. The business purchase account is used to record the purchase of the business. The vendor account is used to record the amount owed to the vendor for the purchase of the business. The ordinary share capital account is used to record the capital contributed by the shareholders of the company.</div>", "topic": "PURCHASES OF BUSINESS : ENTRIES IN THE BOOK OF THE PURCHASER"}, {"id": "objective>Accounts>2012>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> I. The Memorandum of Association of the company  <br/>  II. The Article of Association of the company   <br/>  III. The incorporation documents  <br/>  From the above, which of the following is delivered to registrar of companies for incorporation?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I and II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and III</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">For the incorporation of a company, the following documents are delivered to the registrar of companies: The Memorandum of Association of the company, The Article of Association of the company, and The incorporation documents. The Memorandum of Association outlines the company's relationship with the outside world and the Articles of Association outlines the company's internal affairs and management. The incorporation documents are the legal documents that are used to form the company.</div>", "topic": "COMPANY ACCOUNT : FORMATION OF COMPANY"}, {"id": "objective>Accounts>2012>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When shares are oversubscribed and money is returned to unsuccessful applicants, the entry to record such money is to debit</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">application and allotment account and credit unsubscribed shares</div>", "<div style=\"font-family:Cambria;font-size:17px;\">application and allotment account and credit cash</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oversubscribed shares and credit cash</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oversubscribed shares and credit allotment account</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The accounting entry is to debit application and allotment account(increases) and credit cash(decreases).</div>", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES"}, {"id": "objective>Accounts>2012>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Investing at cost of company is to be disclose under</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">trading accounts </div>", "<div style=\"font-family:Cambria;font-size:17px;\">profit and loss account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">balance sheet </div>", "<div style=\"font-family:Cambria;font-size:17px;\">profit account </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A balance sheet is a financial statement that reports a company's assets, liabilities and shareholders' equity. The balance sheet is one of the three (income statement and statement of cash flows being the other two) core financial statements used to evaluate a business.</div>", "topic": "COMPANY ACCOUNT : FINAL ACCOUNTS OF A LIMITED COMPANY AND TERMINOLOGIES"}, {"id": "objective>Accounts>2012>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the information below to answer this question. <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Purchases </td><td style=\"border:1px solid black;text-align:center;\">₦44880 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Sales </td><td style=\"border:1px solid black;text-align:center;\">₦85850 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Trade creditors</td><td style=\"border:1px solid black;text-align:center;\">₦12250 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Trade debtors </td><td style=\"border:1px solid black;text-align:center;\"> ₦ 24000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Accrued expenses</td><td style=\"border:1px solid black;text-align:center;\"> ₦350 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Prepaid expenses </td><td style=\"border:1px solid black;text-align:center;\"> ₦700 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Stock 1/1/2006</td><td style=\"border:1px solid black;text-align:center;\"> ₦25120 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Stock 31/12/2006 </td><td style=\"border:1px solid black;text-align:center;\">₦27840</td></tr></table></div> <br/>  <br/> Calculate the acid test ratio </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.94:1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.96:1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1:1.94</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.1:96</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Acid-test or quick ratio = Current asset - Closing stock/ Current liabilties <br/>  <br/>                                 Current assets = 24000+ 700+ 27840  = 52540 <br/>                                    Current liabilities = 12250+ 350 = 12600 <br/>  <br/> Therefore Acid ratio = 52540  - 27840/12600 <br/>                                                24700/12600 <br/>                                                        = 1.96:1</div>", "topic": "ACCOUNTING RATIO (2) : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO"}, {"id": "objective>Accounts>2012>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the information below to answer this question. <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Purchases </td><td style=\"border:1px solid black;text-align:center;\">₦44880 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Sales </td><td style=\"border:1px solid black;text-align:center;\">₦85850 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Trade creditors</td><td style=\"border:1px solid black;text-align:center;\">₦12250 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Trade debtors </td><td style=\"border:1px solid black;text-align:center;\"> ₦ 24000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Accrued expenses</td><td style=\"border:1px solid black;text-align:center;\"> ₦350 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Prepaid expenses </td><td style=\"border:1px solid black;text-align:center;\"> ₦700 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Stock 1/1/2006</td><td style=\"border:1px solid black;text-align:center;\"> ₦25120 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Stock 31/12/2006 </td><td style=\"border:1px solid black;text-align:center;\">₦27840</td></tr></table></div> <br/> Determine the number of times stock was turned over during the period to the nearest figure</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Stock turnover = Cost of goods sold /Average stock <br/>  <br/> Cost of goods sold = Opening stock +purchases - Closing stock <br/>                                     = 25120+44880 - 27840 <br/>                                             = 42160 <br/>  <br/> Average stock = Opening stock + Closing stock / 2 <br/>                                 = 25120 + 27840 / 2 <br/>                                              = 52960 / 2 <br/>                                                   = 26480 <br/> Therefore, Stock turnover = 42160 / 26480 <br/>                                                      = 1.59 <br/>                                                     ≏  2</div>", "topic": "ACCOUNTING RATIO (2) : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO"}, {"id": "objective>Accounts>2012>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a source of revenue to the federation account? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Market fees</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bicycle licences</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tariffs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Property rates</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The federation account is a central pool of revenue from which all tiers of government in a federation draw funds. The main sources of revenue to the federation account are oil revenue, company income tax, value added tax, customs and excise duties, and tariffs. Therefore, tariffs are a source of revenue to the federation account.</div>", "topic": "PUBLIC SECTOR ACCOUNTING : SOURCES AND CLASSIFICATION OF GOVERNMENT REVENUE"}, {"id": "objective>Accounts>2012>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The book into which all types of a ministry's expenditure are recorded is the  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ledger book </div>", "<div style=\"font-family:Cambria;font-size:17px;\">payment book </div>", "<div style=\"font-family:Cambria;font-size:17px;\">vote book </div>", "<div style=\"font-family:Cambria;font-size:17px;\">expenditure book</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A vote book is an accounts book which is used to record and monitor expenditure in the public sector.</div>", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES"}, {"id": "objective>Accounts>2012>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Petroleum Technology Development Fund is under the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">general fund </div>", "<div style=\"font-family:Cambria;font-size:17px;\">contingency fund</div>", "<div style=\"font-family:Cambria;font-size:17px;\">trust fund </div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital fund </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Petroleum Technology Development Fund (PTDF) is a parastatal of the Ministry of Petroleum Resources established by Decree 25 of 1973 for the purpose of developing and promoting petroleum technology and for creating the manpower needs of the oil and gas industry through research and training of Nigerians. It is a trust fund, not a general, contingency, or capital fund.</div>", "topic": "PUBLIC SECTOR ACCOUNTING : PURPOSE AND DIFFERENCE BETWEEN GOVERNMENT AND COMMERCIAL ACCOUNTING"}, {"id": "objective>Accounts>2012>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The power to appoint the Auditor General of the federation is vested in the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">National Assembly </div>", "<div style=\"font-family:Cambria;font-size:17px;\">President</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Judical Service Commission </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Civil Service Commission </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The power to appoint the Auditor General of the federation is vested in the President of the country. The Auditor General is appointed by the President on the recommendation of the Federal Civil Service Commission subject to confirmation by the Senate. The National Assembly, Judicial Service Commission, and Civil Service Commission do not have the power to appoint the Auditor General.</div>", "topic": "PUBLIC SECTOR ACCOUNTING : INTRODUCTION AND USERS OF GOVERNMENT ACCOUNTING"}];
